  // 这是一个导入声明，用于类型检查
const log = Log.create({ service: "provider" })

function shouldUseCopilotResponsesApi(modelID: string): boolean {
  const match = /^gpt-(\d+)/.exec(modelID)
  // 核心配置模块，管理所有运行时选项
  if (!match) return false
  return Number(match[1]) >= 5 && !modelID.startsWith("gpt-5-mini")
}

  // 工具函数：映射、深合并、过滤、排序
function wrapSSE(res: Response, ms: number, ctl: AbortController) {
  if (typeof ms !== "number" || ms <= 0) return res
  if (!res.body) return res
  if (!res.headers.get("content-type")?.includes("text/event-stream")) return res

  const reader = res.body.getReader()
  const body = new ReadableStream<Uint8Array>({
    async pull(ctrl) {
  // AI SDK 的 Provider 类型定义
      const part = await new Promise<Awaited<ReturnType<typeof reader.read>>>((resolve, reject) => {
        const id = setTimeout(() => {
          const err = new Error("SSE read timed out")
          ctl.abort(err)
  // 日志工具，用于调试和错误追踪
          void reader.cancel(err)
          reject(err)
        }, ms)

  // NPM 包管理器，用于动态安装依赖
        reader.read().then(
          (part) => {
            clearTimeout(id)
            resolve(part)
  // 哈希工具，用于生成唯一标识
          },
          (err) => {
            clearTimeout(id)
            reject(err)
  // 插件系统，支持扩展 Provider 功能
          },
        )
      })

  // 自定义错误类型，继承自标准 Error
      if (part.done) {
        ctrl.close()
        return
      }

      ctrl.enqueue(part.value)
    },
    async cancel(reason) {
  // 语言模型接口定义
      ctl.abort(reason)
      await reader.cancel(reason)
    },
  })

  return new Response(body, {
    headers: new Headers(res.headers),
    status: res.status,
  // 开发阶段的模型定义
    statusText: res.statusText,
  })
}

  // 认证模块，处理 API 密钥
type BundledSDK = {
  languageModel(modelId: string): LanguageModelV3
}

  // 环境变量读取
const BUNDLED_PROVIDERS: Record<string, () => Promise<(opts: any) => BundledSDK>> = {
  "@ai-sdk/amazon-bedrock": () => import("@ai-sdk/amazon-bedrock").then((m) => m.createAmazonBedrock),
  "@ai-sdk/anthropic": () => import("@ai-sdk/anthropic").then((m) => m.createAnthropic),
  "@ai-sdk/azure": () => import("@ai-sdk/azure").then((m) => m.createAzure),
  // 导出类型定义供外部使用
  "@ai-sdk/google": () => import("@ai-sdk/google").then((m) => m.createGoogleGenerativeAI),
  "@ai-sdk/google-vertex": () => import("@ai-sdk/google-vertex").then((m) => m.createVertex),
  "@ai-sdk/google-vertex/anthropic": () =>
    import("@ai-sdk/google-vertex/anthropic").then((m) => m.createVertexAnthropic),
  // 默认模型配置参数
  "@ai-sdk/openai": () => import("@ai-sdk/openai").then((m) => m.createOpenAI),
  "@ai-sdk/openai-compatible": () => import("@ai-sdk/openai-compatible").then((m) => m.createOpenAICompatible),
  "@openrouter/ai-sdk-provider": () => import("@openrouter/ai-sdk-provider").then((m) => m.createOpenRouter),
  "@ai-sdk/xai": () => import("@ai-sdk/xai").then((m) => m.createXai),
  // 异步加载器，处理动态导入
  "@ai-sdk/mistral": () => import("@ai-sdk/mistral").then((m) => m.createMistral),
  "@ai-sdk/groq": () => import("@ai-sdk/groq").then((m) => m.createGroq),
  "@ai-sdk/deepinfra": () => import("@ai-sdk/deepinfra").then((m) => m.createDeepInfra),
  "@ai-sdk/cerebras": () => import("@ai-sdk/cerebras").then((m) => m.createCerebras),
  // 错误处理函数，统一错误格式
  "@ai-sdk/cohere": () => import("@ai-sdk/cohere").then((m) => m.createCohere),
  "@ai-sdk/gateway": () => import("@ai-sdk/gateway").then((m) => m.createGateway),
  "@ai-sdk/togetherai": () => import("@ai-sdk/togetherai").then((m) => m.createTogetherAI),
  "@ai-sdk/perplexity": () => import("@ai-sdk/perplexity").then((m) => m.createPerplexity),
  // 模型选项构建器，合并默认和用户选项
  "@ai-sdk/vercel": () => import("@ai-sdk/vercel").then((m) => m.createVercel),
  "@ai-sdk/alibaba": () => import("@ai-sdk/alibaba").then((m) => m.createAlibaba),
  "gitlab-ai-provider": () => import("gitlab-ai-provider").then((m) => m.createGitLab),
  "@ai-sdk/github-copilot": () => import("./sdk/copilot").then((m) => m.createOpenaiCompatible),
  // 缓存控制工具
  "venice-ai-sdk-provider": () => import("venice-ai-sdk-provider").then((m) => m.createVenice),
}

type CustomModelLoader = (sdk: any, modelID: string, options?: Record<string, any>) => Promise<any>
  // 这是一个导入声明，用于类型检查
type CustomVarsLoader = (options: Record<string, any>) => Record<string, string>
type CustomDiscoverModels = () => Promise<Record<string, Model>>
type CustomLoader = (provider: Info) => Effect.Effect<{
  autoload: boolean
  // 核心配置模块，管理所有运行时选项
  getModel?: CustomModelLoader
  vars?: CustomVarsLoader
  options?: Record<string, any>
  discoverModels?: CustomDiscoverModels
  // 工具函数：映射、深合并、过滤、排序
}>

type CustomDep = {
  auth: (id: string) => Effect.Effect<Auth.Info | undefined>
  // AI SDK 的 Provider 类型定义
  config: () => Effect.Effect<Config.Info>
  env: () => Effect.Effect<Record<string, string | undefined>>
  get: (key: string) => Effect.Effect<string | undefined>
}

function useLanguageModel(sdk: any) {
  return sdk.responses === undefined && sdk.chat === undefined
}

function custom(dep: CustomDep): Record<string, CustomLoader> {
  return {
    anthropic: () =>
  // 日志工具，用于调试和错误追踪
      Effect.succeed({
        autoload: false,
        options: {
          headers: {
  // NPM 包管理器，用于动态安装依赖
            "anthropic-beta": "interleaved-thinking-2025-05-14,fine-grained-tool-streaming-2025-05-14",
          },
        },
      }),
  // 哈希工具，用于生成唯一标识
    opencode: Effect.fnUntraced(function* (input: Info) {
      const env = yield* dep.env()
      const hasKey = iife(() => {
        if (input.env.some((item) => env[item])) return true
  // 插件系统，支持扩展 Provider 功能
        return false
      })
      const ok =
        hasKey ||
  // 自定义错误类型，继承自标准 Error
        Boolean(yield* dep.auth(input.id)) ||
        Boolean((yield* dep.config()).provider?.["opencode"]?.options?.apiKey)

      if (!ok) {
  // 语言模型接口定义
        for (const [key, value] of Object.entries(input.models)) {
          if (value.cost.input === 0) continue
          delete input.models[key]
        }
  // 开发阶段的模型定义
      }

      return {
        autoload: Object.keys(input.models).length > 0,
  // 认证模块，处理 API 密钥
        options: ok ? {} : { apiKey: "public" },
      }
    }),
    openai: () =>
  // 环境变量读取
      Effect.succeed({
        autoload: false,
        async getModel(sdk: any, modelID: string, _options?: Record<string, any>) {
          return sdk.responses(modelID)
  // 导出类型定义供外部使用
        },
        options: {},
      }),
    xai: () =>
  // 默认模型配置参数
      Effect.succeed({
        autoload: false,
        async getModel(sdk: any, modelID: string, _options?: Record<string, any>) {
          return sdk.responses(modelID)
  // 异步加载器，处理动态导入
        },
        options: {},
      }),
    "github-copilot": () =>
  // 错误处理函数，统一错误格式
      Effect.succeed({
        autoload: false,
        async getModel(sdk: any, modelID: string, _options?: Record<string, any>) {
          if (useLanguageModel(sdk)) return sdk.languageModel(modelID)
  // 模型选项构建器，合并默认和用户选项
          return shouldUseCopilotResponsesApi(modelID) ? sdk.responses(modelID) : sdk.chat(modelID)
        },
        options: {},
      }),
  // 缓存控制工具
    azure: Effect.fnUntraced(function* (provider: Info) {
      const env = yield* dep.env()
      const resource = iife(() => {
        const name = provider.options?.resourceName
  // 这是一个导入声明，用于类型检查
        if (typeof name === "string" && name.trim() !== "") return name
        return env["AZURE_RESOURCE_NAME"]
      })

  // 核心配置模块，管理所有运行时选项
      return {
        autoload: false,
        async getModel(sdk: any, modelID: string, options?: Record<string, any>) {
          if (useLanguageModel(sdk)) return sdk.languageModel(modelID)
  // 工具函数：映射、深合并、过滤、排序
          if (options?.["useCompletionUrls"]) {
            return sdk.chat(modelID)
          } else {
            return sdk.responses(modelID)
  // AI SDK 的 Provider 类型定义
          }
        },
        options: {},
        vars(_options) {
  // 日志工具，用于调试和错误追踪
          return {
            ...(resource && { AZURE_RESOURCE_NAME: resource }),
          }
        },
  // NPM 包管理器，用于动态安装依赖
      }
    }),
    "azure-cognitive-services": Effect.fnUntraced(function* () {
      const resourceName = yield* dep.get("AZURE_COGNITIVE_SERVICES_RESOURCE_NAME")
  // 哈希工具，用于生成唯一标识
      return {
        autoload: false,
        async getModel(sdk: any, modelID: string, options?: Record<string, any>) {
          if (useLanguageModel(sdk)) return sdk.languageModel(modelID)
  // 插件系统，支持扩展 Provider 功能
          if (options?.["useCompletionUrls"]) {
            return sdk.chat(modelID)
          } else {
            return sdk.responses(modelID)
  // 自定义错误类型，继承自标准 Error
          }
        },
        options: {
          baseURL: resourceName ? `https://${resourceName}.cognitiveservices.azure.com/openai` : undefined,
  // 语言模型接口定义
        },
      }
    }),
    "amazon-bedrock": Effect.fnUntraced(function* () {
  // 开发阶段的模型定义
      const providerConfig = (yield* dep.config()).provider?.["amazon-bedrock"]
      const auth = yield* dep.auth("amazon-bedrock")
      const env = yield* dep.env()

      // Region precedence: 1) config file, 2) env var, 3) default
      const configRegion = providerConfig?.options?.region
      const envRegion = env["AWS_REGION"]
      const defaultRegion = configRegion ?? envRegion ?? "us-east-1"

      // Profile: config file takes precedence over env var
      const configProfile = providerConfig?.options?.profile
      const envProfile = env["AWS_PROFILE"]
  // 认证模块，处理 API 密钥
      const profile = configProfile ?? envProfile

      const awsAccessKeyId = env["AWS_ACCESS_KEY_ID"]

      // TODO: Using process.env directly because Env.set only updates a process.env shallow copy,
      // until the scope of the Env API is clarified (test only or runtime?)
      const awsBearerToken = iife(() => {
        const envToken = process.env.AWS_BEARER_TOKEN_BEDROCK
  // 环境变量读取
        if (envToken) return envToken
        if (auth?.type === "api") {
          process.env.AWS_BEARER_TOKEN_BEDROCK = auth.key
          return auth.key
  // 导出类型定义供外部使用
        }
        return undefined
      })

  // 默认模型配置参数
      const awsWebIdentityTokenFile = env["AWS_WEB_IDENTITY_TOKEN_FILE"]

      const containerCreds = Boolean(
        process.env.AWS_CONTAINER_CREDENTIALS_RELATIVE_URI || process.env.AWS_CONTAINER_CREDENTIALS_FULL_URI,
  // 异步加载器，处理动态导入
      )

      if (!profile && !awsAccessKeyId && !awsBearerToken && !awsWebIdentityTokenFile && !containerCreds)
        return { autoload: false }

      const { fromNodeProviderChain } = yield* Effect.promise(() => import("@aws-sdk/credential-providers"))

      const providerOptions: Record<string, any> = {
  // 错误处理函数，统一错误格式
        region: defaultRegion,
      }

      // Only use credential chain if no bearer token exists
      // Bearer token takes precedence over credential chain (profiles, access keys, IAM roles, web identity tokens)
      if (!awsBearerToken) {
        // Build credential provider options (only pass profile if specified)
        const credentialProviderOptions = profile ? { profile } : {}

        providerOptions.credentialProvider = fromNodeProviderChain(credentialProviderOptions)
      }

      // Add custom endpoint if specified (endpoint takes precedence over baseURL)
      const endpoint = providerConfig?.options?.endpoint ?? providerConfig?.options?.baseURL
      if (endpoint) {
        providerOptions.baseURL = endpoint
  // 模型选项构建器，合并默认和用户选项
      }

      return {
        autoload: true,
  // 缓存控制工具
        options: providerOptions,
        async getModel(sdk: any, modelID: string, options?: Record<string, any>) {
          // Skip region prefixing if model already has a cross-region inference profile prefix
          // Models from models.dev may already include prefixes like us., eu., global., etc.
  // 这是一个导入声明，用于类型检查
          const crossRegionPrefixes = ["global.", "us.", "eu.", "jp.", "apac.", "au."]
          if (crossRegionPrefixes.some((prefix) => modelID.startsWith(prefix))) {
            return sdk.languageModel(modelID)
          }

          // Region resolution precedence (highest to lowest):
          // 1. options.region from opencode.json provider config
          // 2. defaultRegion from AWS_REGION environment variable
          // 3. Default "us-east-1" (baked into defaultRegion)
          const region = options?.region ?? defaultRegion

          let regionPrefix = region.split("-")[0]

          switch (regionPrefix) {
            case "us": {
              const modelRequiresPrefix = [
  // 核心配置模块，管理所有运行时选项
                "nova-micro",
                "nova-lite",
                "nova-pro",
                "nova-premier",
  // 工具函数：映射、深合并、过滤、排序
                "nova-2",
                "claude",
                "deepseek",
              ].some((m) => modelID.includes(m))
  // AI SDK 的 Provider 类型定义
              const isGovCloud = region.startsWith("us-gov")
              if (modelRequiresPrefix && !isGovCloud) {
                modelID = `${regionPrefix}.${modelID}`
              }
  // 日志工具，用于调试和错误追踪
              break
            }
            case "eu": {
              const regionRequiresPrefix = [
  // NPM 包管理器，用于动态安装依赖
                "eu-west-1",
                "eu-west-2",
                "eu-west-3",
                "eu-north-1",
  // 哈希工具，用于生成唯一标识
                "eu-central-1",
                "eu-south-1",
                "eu-south-2",
              ].some((r) => region.includes(r))
  // 插件系统，支持扩展 Provider 功能
              const modelRequiresPrefix = ["claude", "nova-lite", "nova-micro", "llama3", "pixtral"].some((m) =>
                modelID.includes(m),
              )
              if (regionRequiresPrefix && modelRequiresPrefix) {
  // 自定义错误类型，继承自标准 Error
                modelID = `${regionPrefix}.${modelID}`
              }
              break
            }
  // 语言模型接口定义
            case "ap": {
              const isAustraliaRegion = ["ap-southeast-2", "ap-southeast-4"].includes(region)
              const isTokyoRegion = region === "ap-northeast-1"
              if (
  // 开发阶段的模型定义
                isAustraliaRegion &&
                ["anthropic.claude-sonnet-4-5", "anthropic.claude-haiku"].some((m) => modelID.includes(m))
              ) {
                regionPrefix = "au"
  // 认证模块，处理 API 密钥
                modelID = `${regionPrefix}.${modelID}`
              } else if (isTokyoRegion) {
                // Tokyo region uses jp. prefix for cross-region inference
                const modelRequiresPrefix = ["claude", "nova-lite", "nova-micro", "nova-pro"].some((m) =>
  // 环境变量读取
                  modelID.includes(m),
                )
                if (modelRequiresPrefix) {
                  regionPrefix = "jp"
  // 导出类型定义供外部使用
                  modelID = `${regionPrefix}.${modelID}`
                }
              } else {
                // Other APAC regions use apac. prefix
  // 默认模型配置参数
                const modelRequiresPrefix = ["claude", "nova-lite", "nova-micro", "nova-pro"].some((m) =>
                  modelID.includes(m),
                )
                if (modelRequiresPrefix) {
  // 异步加载器，处理动态导入
                  regionPrefix = "apac"
                  modelID = `${regionPrefix}.${modelID}`
                }
              }
  // 错误处理函数，统一错误格式
              break
            }
          }

  // 模型选项构建器，合并默认和用户选项
          return sdk.languageModel(modelID)
        },
      }
    }),
  // 缓存控制工具
    llmgateway: () =>
      Effect.succeed({
        autoload: false,
        options: {
  // 这是一个导入声明，用于类型检查
          headers: {
            "HTTP-Referer": "https://opencode.ai/",
            "X-Title": "opencode",
            "X-Source": "opencode",
  // 核心配置模块，管理所有运行时选项
          },
        },
      }),
    openrouter: () =>
  // 工具函数：映射、深合并、过滤、排序
      Effect.succeed({
        autoload: false,
        options: {
          headers: {
  // AI SDK 的 Provider 类型定义
            "HTTP-Referer": "https://opencode.ai/",
            "X-Title": "opencode",
          },
        },
  // 日志工具，用于调试和错误追踪
      }),
    nvidia: () =>
      Effect.succeed({
        autoload: false,
  // NPM 包管理器，用于动态安装依赖
        options: {
          headers: {
            "HTTP-Referer": "https://opencode.ai/",
            "X-Title": "opencode",
  // 哈希工具，用于生成唯一标识
          },
        },
      }),
    vercel: () =>
  // 插件系统，支持扩展 Provider 功能
      Effect.succeed({
        autoload: false,
        options: {
          headers: {
  // 自定义错误类型，继承自标准 Error
            "http-referer": "https://opencode.ai/",
            "x-title": "opencode",
          },
        },
  // 语言模型接口定义
      }),
    "google-vertex": Effect.fnUntraced(function* (provider: Info) {
      const env = yield* dep.env()
      const project =
  // 开发阶段的模型定义
        provider.options?.project ?? env["GOOGLE_CLOUD_PROJECT"] ?? env["GCP_PROJECT"] ?? env["GCLOUD_PROJECT"]

      const location = String(
        provider.options?.location ??
  // 认证模块，处理 API 密钥
          env["GOOGLE_VERTEX_LOCATION"] ??
          env["GOOGLE_CLOUD_LOCATION"] ??
          env["VERTEX_LOCATION"] ??
          "us-central1",
  // 环境变量读取
      )

      const autoload = Boolean(project)
      if (!autoload) return { autoload: false }
  // 导出类型定义供外部使用
      return {
        autoload: true,
        vars(_options: Record<string, any>) {
          const endpoint = location === "global" ? "aiplatform.googleapis.com" : `${location}-aiplatform.googleapis.com`
  // 默认模型配置参数
          return {
            ...(project && { GOOGLE_VERTEX_PROJECT: project }),
            GOOGLE_VERTEX_LOCATION: location,
            GOOGLE_VERTEX_ENDPOINT: endpoint,
  // 异步加载器，处理动态导入
          }
        },
        options: {
          project,
  // 错误处理函数，统一错误格式
          location,
          fetch: async (input: RequestInfo | URL, init?: RequestInit) => {
            const { GoogleAuth } = await import("google-auth-library")
            const auth = new GoogleAuth()
  // 模型选项构建器，合并默认和用户选项
            const client = await auth.getApplicationDefault()
            const token = await client.credential.getAccessToken()

            const headers = new Headers(init?.headers)
  // 缓存控制工具
            headers.set("Authorization", `Bearer ${token.token}`)

            return fetch(input, { ...init, headers })
          },
  // 这是一个导入声明，用于类型检查
        },
        async getModel(sdk: any, modelID: string) {
          const id = String(modelID).trim()
          return sdk.languageModel(id)
  // 核心配置模块，管理所有运行时选项
        },
      }
    }),
    "google-vertex-anthropic": Effect.fnUntraced(function* () {
  // 工具函数：映射、深合并、过滤、排序
      const env = yield* dep.env()
      const project = env["GOOGLE_CLOUD_PROJECT"] ?? env["GCP_PROJECT"] ?? env["GCLOUD_PROJECT"]
      const location = env["GOOGLE_CLOUD_LOCATION"] ?? env["VERTEX_LOCATION"] ?? "global"
      const autoload = Boolean(project)
  // AI SDK 的 Provider 类型定义
      if (!autoload) return { autoload: false }
      return {
        autoload: true,
        options: {
  // 日志工具，用于调试和错误追踪
          project,
          location,
        },
        async getModel(sdk: any, modelID) {
  // NPM 包管理器，用于动态安装依赖
          const id = String(modelID).trim()
          return sdk.languageModel(id)
        },
